/**
 * Organization Module Service
 *
 * Business logic service for the Organization module.
 * Handles organization CRUD, settings management, and tenant operations.
 *
 * @module modules/_core/organization/organization.service
 *
 * @example
 * ```typescript
 * import { OrganizationService } from '@/modules/_core/organization/organization.service';
 * import { resolve } from '@/core/kernel/container';
 *
 * const orgService = resolve<OrganizationService>('OrganizationService');
 *
 * // Create a new organization
 * const result = await orgService.create({
 *   name: 'My Restaurant',
 *   email: 'contact@myrestaurant.com',
 * });
 * ```
 */

import { injectable, inject } from 'tsyringe';
import { OrganizationStatus, Prisma } from '@prisma/client';

import { TOKENS } from '@/core/kernel/container';
import { AppException } from '@/core/exceptions/app.exception';
import { EventService } from '@/core/services/event.service';

import { OrganizationRepository, PaginatedResult } from '@/modules/_core/organization/organization.repository';

import type {
  Organization,
  OrganizationWithRelations,
  CreateOrganizationRequest,
  CreateOrganizationResponse,
  UpdateOrganizationRequest,
  UpdateOrganizationResponse,
  UpdateSettingsRequest,
  UpdateSettingsResponse,
  ChangeStatusRequest,
  ChangeStatusResponse,
  OrganizationListParams,
  OrganizationSummary,
  OrganizationSettings,
} from '@/modules/_core/organization/organization.types';

import {
  createOrganizationSchema,
  updateOrganizationSchema,
  updateSettingsSchema,
  changeStatusSchema,
  organizationListQuerySchema,
  generateSlug,
  type CreateOrganizationInput,
  type UpdateOrganizationInput,
  type UpdateSettingsInput,
  type ChangeStatusInput,
  type OrganizationListQueryInput,
} from '@/modules/_core/organization/organization.schema';

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

/**
 * User context for operations
 */
interface UserContext {
  /** User ID making the request */
  userId?: string;
  /** Whether user is a platform admin */
  isPlatformAdmin?: boolean;
}

// -----------------------------------------------------------------------------
// Organization Service
// -----------------------------------------------------------------------------

/**
 * Organization module business logic service.
 *
 * Handles all organization-related business operations including:
 * - Organization CRUD operations
 * - Settings management
 * - Status changes
 * - Tenant lifecycle operations
 *
 * @example
 * ```typescript
 * @injectable()
 * class SomeController {
 *   constructor(
 *     @inject('OrganizationService') private orgService: OrganizationService,
 *   ) {}
 *
 *   async handleCreate(req: Request, res: Response) {
 *     const result = await this.orgService.create(req.body);
 *     res.json(result);
 *   }
 * }
 * ```
 */
@injectable()
export class OrganizationService {
  constructor(
    @inject('OrganizationRepository') private readonly repository: OrganizationRepository,
    @inject(TOKENS.EventService) private readonly eventService: EventService
  ) {}

  // ---------------------------------------------------------------------------
  // Read Operations
  // ---------------------------------------------------------------------------

  /**
   * Lists organizations with pagination and filtering.
   *
   * @param params - Query parameters
   * @returns Paginated list of organizations
   *
   * @example
   * ```typescript
   * const result = await orgService.list({
   *   page: 1,
   *   perPage: 10,
   *   status: 'ACTIVE',
   * });
   * ```
   */
  async list(params: OrganizationListParams): Promise<PaginatedResult<Organization>> {
    const validated = this.validateInput(params, organizationListQuerySchema) as OrganizationListQueryInput;
    return this.repository.findAll(validated);
  }

  /**
   * Lists organization summaries (for dropdowns, etc.).
   *
   * @param params - Optional filtering params
   * @returns Array of organization summaries
   */
  async listSummaries(params?: Partial<OrganizationListParams>): Promise<OrganizationSummary[]> {
    return this.repository.findAllSummaries(params);
  }

  /**
   * Gets an organization by ID.
   *
   * @param id - Organization ID
   * @returns Organization or null
   */
  async getById(id: string): Promise<Organization | null> {
    return this.repository.findById(id);
  }

  /**
   * Gets an organization by ID with relations.
   *
   * @param id - Organization ID
   * @returns Organization with relations
   * @throws {AppException} If not found
   */
  async getByIdWithRelations(id: string): Promise<OrganizationWithRelations> {
    const organization = await this.repository.findByIdWithRelations(id);

    if (!organization) {
      throw AppException.notFound('Organization', id);
    }

    return organization;
  }

  /**
   * Gets an organization by ID or throws.
   *
   * @param id - Organization ID
   * @returns Organization
   * @throws {AppException} If not found
   */
  async getByIdOrThrow(id: string): Promise<Organization> {
    return this.repository.findByIdOrThrow(id);
  }

  /**
   * Gets an organization by slug.
   *
   * @param slug - Organization slug
   * @returns Organization or null
   */
  async getBySlug(slug: string): Promise<Organization | null> {
    return this.repository.findBySlug(slug);
  }

  /**
   * Gets an organization by slug or throws.
   *
   * @param slug - Organization slug
   * @returns Organization
   * @throws {AppException} If not found
   */
  async getBySlugOrThrow(slug: string): Promise<Organization> {
    return this.repository.findBySlugOrThrow(slug);
  }

  /**
   * Gets organization settings.
   *
   * @param id - Organization ID
   * @returns Organization settings
   * @throws {AppException} If not found
   */
  async getSettings(id: string): Promise<OrganizationSettings> {
    const organization = await this.repository.findByIdOrThrow(id);
    return organization.settings;
  }

  /**
   * Counts organizations by status.
   *
   * @param status - Optional status filter
   * @returns Count
   */
  async count(status?: OrganizationStatus): Promise<number> {
    return this.repository.count(status);
  }

  // ---------------------------------------------------------------------------
  // Write Operations
  // ---------------------------------------------------------------------------

  /**
   * Creates a new organization.
   *
   * Validates input, generates slug if not provided, creates organization,
   * and emits creation event.
   *
   * @param data - Create request data
   * @param context - User context
   * @returns Created organization response
   * @throws {AppException} If slug or email already exists
   *
   * @example
   * ```typescript
   * const result = await orgService.create({
   *   name: 'My Restaurant',
   *   email: 'contact@myrestaurant.com',
   * });
   * console.log('Created:', result.organization.id);
   * ```
   */
  async create(
    data: CreateOrganizationRequest,
    context?: UserContext
  ): Promise<CreateOrganizationResponse> {
    // Validate input
    const validated = this.validateInput(data, createOrganizationSchema) as CreateOrganizationInput;

    // Generate slug if not provided
    let slug = validated.slug;
    if (!slug) {
      slug = generateSlug(validated.name);
      // Ensure uniqueness
      let counter = 1;
      let baseSlug = slug;
      while (await this.repository.slugExists(slug)) {
        slug = `${baseSlug}-${counter}`;
        counter++;
      }
    } else {
      // Check if provided slug exists
      if (await this.repository.slugExists(slug)) {
        throw AppException.alreadyExists('Organization slug', slug);
      }
    }

    // Check if email exists
    if (await this.repository.emailExists(validated.email)) {
      throw AppException.alreadyExists('Organization email', validated.email);
    }

    // Create organization
    const organization = await this.repository.create({
      name: validated.name,
      slug,
      email: validated.email,
      phone: validated.phone || null,
      settings: (validated.settings || {}) as Prisma.JsonValue,
      status: OrganizationStatus.ACTIVE,
    });

    // Emit creation event
    await this.eventService.emitCustom('organization.created', {
      organizationId: organization.id,
      name: organization.name,
      slug: organization.slug,
      createdBy: context?.userId,
      timestamp: new Date().toISOString(),
    });

    return {
      organization,
      message: 'Organization created successfully.',
    };
  }

  /**
   * Updates an organization.
   *
   * @param id - Organization ID
   * @param data - Update request data
   * @param context - User context
   * @returns Updated organization response
   * @throws {AppException} If not found or slug/email conflicts
   */
  async update(
    id: string,
    data: UpdateOrganizationRequest,
    context?: UserContext
  ): Promise<UpdateOrganizationResponse> {
    // Validate input
    const validated = this.validateInput(data, updateOrganizationSchema) as UpdateOrganizationInput;

    // Get current organization
    const current = await this.repository.findByIdOrThrow(id);

    // Check slug uniqueness if changing
    if (validated.slug && validated.slug !== current.slug) {
      if (await this.repository.slugExists(validated.slug, id)) {
        throw AppException.alreadyExists('Organization slug', validated.slug);
      }
    }

    // Check email uniqueness if changing
    if (validated.email && validated.email.toLowerCase() !== current.email.toLowerCase()) {
      if (await this.repository.emailExists(validated.email, id)) {
        throw AppException.alreadyExists('Organization email', validated.email);
      }
    }

    // Build update data
    const updateData: Record<string, unknown> = {};
    if (validated.name !== undefined) updateData.name = validated.name;
    if (validated.slug !== undefined) updateData.slug = validated.slug;
    if (validated.email !== undefined) updateData.email = validated.email;
    if (validated.phone !== undefined) updateData.phone = validated.phone;
    if (validated.logo !== undefined) updateData.logo = validated.logo;

    // Update organization
    const organization = await this.repository.update(id, updateData);

    // Emit update event
    await this.eventService.emitCustom('organization.updated', {
      organizationId: organization.id,
      changes: updateData,
      updatedBy: context?.userId,
      timestamp: new Date().toISOString(),
    });

    return {
      organization,
      message: 'Organization updated successfully.',
    };
  }

  /**
   * Updates organization settings.
   *
   * Settings are merged with existing settings, not replaced.
   *
   * @param id - Organization ID
   * @param data - Settings update request
   * @param context - User context
   * @returns Updated settings response
   */
  async updateSettings(
    id: string,
    data: UpdateSettingsRequest,
    context?: UserContext
  ): Promise<UpdateSettingsResponse> {
    // Validate input
    const validated = this.validateInput(data, updateSettingsSchema) as UpdateSettingsInput;

    // Get current settings
    const current = await this.repository.findByIdOrThrow(id);
    const previousSettings = current.settings;

    // Update settings (merge)
    const organization = await this.repository.updateSettings(
      id,
      validated.settings as Prisma.JsonValue
    );

    // Emit settings update event
    await this.eventService.emitCustom('organization.settings.updated', {
      organizationId: organization.id,
      previousSettings,
      newSettings: organization.settings,
      updatedBy: context?.userId,
      timestamp: new Date().toISOString(),
    });

    return {
      settings: organization.settings,
      message: 'Organization settings updated successfully.',
    };
  }

  /**
   * Changes organization status.
   *
   * @param id - Organization ID
   * @param data - Status change request
   * @param context - User context
   * @returns Status change response
   */
  async changeStatus(
    id: string,
    data: ChangeStatusRequest,
    context?: UserContext
  ): Promise<ChangeStatusResponse> {
    // Validate input
    const validated = this.validateInput(data, changeStatusSchema) as ChangeStatusInput;

    // Get current organization
    const current = await this.repository.findByIdOrThrow(id);
    const previousStatus = current.status;

    // Check if status is actually changing
    if (previousStatus === validated.status) {
      return {
        organization: current,
        previousStatus,
        message: 'Status unchanged.',
      };
    }

    // Update status
    const organization = await this.repository.updateStatus(id, validated.status);

    // Emit status change event
    await this.eventService.emitCustom('organization.status.changed', {
      organizationId: organization.id,
      previousStatus,
      newStatus: validated.status,
      reason: validated.reason,
      changedBy: context?.userId,
      timestamp: new Date().toISOString(),
    });

    return {
      organization,
      previousStatus,
      message: `Organization status changed to ${validated.status}.`,
    };
  }

  // ---------------------------------------------------------------------------
  // Delete Operations
  // ---------------------------------------------------------------------------

  /**
   * Soft deletes an organization.
   *
   * @param id - Organization ID
   * @param context - User context
   * @throws {AppException} If not found
   *
   * @example
   * ```typescript
   * await orgService.delete('org_123');
   * ```
   */
  async delete(id: string, context?: UserContext): Promise<void> {
    const organization = await this.repository.findByIdOrThrow(id);

    // Soft delete
    await this.repository.softDelete(id);

    // Emit deletion event
    await this.eventService.emitCustom('organization.deleted', {
      organizationId: organization.id,
      name: organization.name,
      deletedBy: context?.userId,
      timestamp: new Date().toISOString(),
    });
  }

  /**
   * Restores a soft-deleted organization.
   *
   * @param id - Organization ID
   * @param context - User context
   * @returns Restored organization
   */
  async restore(id: string, context?: UserContext): Promise<Organization> {
    const organization = await this.repository.restore(id);

    // Emit restore event
    await this.eventService.emitCustom('organization.restored', {
      organizationId: organization.id,
      name: organization.name,
      restoredBy: context?.userId,
      timestamp: new Date().toISOString(),
    });

    return organization;
  }

  // ---------------------------------------------------------------------------
  // Validation Operations
  // ---------------------------------------------------------------------------

  /**
   * Checks if a slug is available.
   *
   * @param slug - Slug to check
   * @param excludeId - Optional ID to exclude
   * @returns True if available
   */
  async isSlugAvailable(slug: string, excludeId?: string): Promise<boolean> {
    return !(await this.repository.slugExists(slug, excludeId));
  }

  /**
   * Checks if an email is available.
   *
   * @param email - Email to check
   * @param excludeId - Optional ID to exclude
   * @returns True if available
   */
  async isEmailAvailable(email: string, excludeId?: string): Promise<boolean> {
    return !(await this.repository.emailExists(email, excludeId));
  }

  // ---------------------------------------------------------------------------
  // Helper Methods
  // ---------------------------------------------------------------------------

  /**
   * Validates input data against a Zod schema.
   */
  private validateInput<T>(data: unknown, schema: { parse: (data: unknown) => T }): T {
    try {
      return schema.parse(data);
    } catch (error) {
      if (error && typeof error === 'object' && 'errors' in error) {
        const zodError = error as { errors: Array<{ path: string[]; message: string; code: string }> };
        const validationErrors = zodError.errors.map((err) => ({
          field: err.path.join('.'),
          message: err.message,
          rule: err.code,
        }));
        throw AppException.validation(validationErrors);
      }
      throw error;
    }
  }
}
